-- Insert Episode 5: Psychosocial Integrity and Patient Assessment
INSERT INTO study_guides (episode_id, title, short_answer_questions, essay_questions, glossary)
VALUES (
  5,
  'Comprehensive Study Guide: Psychosocial Integrity and Patient Assessment',
  '[
    {"question": "What is the primary difference between violent and non-violent physical restraints, and what is a key federal guideline for their use?", "answer": "Violent physical restraints are used to control aggressive patient behavior, while non-violent restraints are used to ensure patient safety in a clinical context, such as preventing an individual from pulling out an IV line. A key federal guideline is that all restraints require a physician''s order, which is time-limited, and a nurse must remove the restraints and assess the patient at least every two hours."},
    {"question": "According to Peplau, what are the four levels of anxiety? Briefly describe the most extreme level.", "answer": "Peplau''s four levels of anxiety are mild, moderate, severe, and panic. The most extreme level, panic, is associated with feelings of dread and terror, and the individual is unable to perform any other tasks, no matter how strongly they are persuaded to do so."},
    {"question": "List and explain three essential components that should be included in a nursing health history.", "answer": "Essential components of a nursing health history include: Chief Complaint (the history of the present illness, including the date of onset, descriptions of symptoms, and any aggravating factors), Past Medical History (information about the patient''s usual health status, past medical or surgical problems, immunization status, current medications, and allergies), and Family History (information that may reveal a risk for certain medical conditions that have a genetic, familial, or environmental link)."},
    {"question": "Describe the key differences in approach between the Authoritarian and Authoritative parenting styles.", "answer": "Authoritarian parents desire absolute obedience without question, using harsh punishments and their power to impose decisions, which can lead to children who are less independent. In contrast, Authoritative parents provide boundaries and expect obedience but also consider the child''s unique position, helping their children to develop higher self-esteem and confidence."},
    {"question": "What are the five stages of grief as defined by the Kübler-Ross model?", "answer": "The five stages of grief in the Kübler-Ross model are: Denial (refusing to accept the reality of the situation), Anger (feeling angry about the situation), Bargaining (attempting to make a deal with a higher power), Depression (anticipating the loss with sadness and helplessness), and Acceptance (being ready to face the impending death or loss)."},
    {"question": "Explain the fundamental premise of Trauma-Informed Care and list two of its five core elements.", "answer": "Trauma-Informed Care is based on the premise that many individuals have experienced some form of trauma, and therefore every patient should be approached with sensitivity and care. Its five core elements are Safety (ensuring the patient feels physically and emotionally safe), Choice (respecting the individual''s right to choose), Trustworthiness, Collaboration, and Empowerment."},
    {"question": "What is the distinction between palliative care and hospice care in terms of patient eligibility and goals?", "answer": "Palliative care aims to make life as comfortable as possible by treating distressing symptoms of chronic disease and can be implemented for any patient, regardless of their prognosis. Hospice care is specifically for patients with a terminal diagnosis and a life expectancy of six months or less, focusing on supporting the patient and family through the dying process."},
    {"question": "Define the physical examination technique of percussion and name two of the five sounds it can produce.", "answer": "Percussion is the technique of striking a part of the body to set the chest or abdominal wall into motion, producing a sound that helps determine if the underlying tissue is solid, air-filled, or fluid-filled. Two sounds it can produce are Tympany (a hollow, drum-like sound) and Dullness (a dull sound heard over dense structures like the liver)."},
    {"question": "In Aaron Beck''s Cognitive Therapy, what is the \"triad of cognitive thoughts\" that contributes to depression?", "answer": "The \"triad of cognitive thoughts\" in Aaron Beck''s Cognitive Therapy consists of a client''s negative thoughts about three areas: 1) the self, 2) the world/environment, and 3) the future."},
    {"question": "Identify four potential indicators of abuse that might be revealed during the collection of a patient''s history.", "answer": "Potential indicators of abuse in a patient''s history include: vague explanations for injuries, inconsistencies between physical findings and the explanation given, a long period of time between the injury and seeking treatment, and a personal or family history of violent death or substance abuse. Other indicators are a history of previous injuries or spontaneous abortions."}
  ]'::jsonb,
  '[
    {"question": "Discuss the critical role of therapeutic communication in nursing. Compare and contrast at least three facilitating techniques (e.g., Empathy, Exploration, Encouragement) with three non-therapeutic techniques (e.g., Providing advice, Disagreeing, Devaluing patient''s feelings), providing specific examples for each.", "guidance": "Formulate a comprehensive essay response for each."},
    {"question": "A healthcare provider suspects an adult patient is a victim of domestic violence. Outline the 7 steps for identifying and assisting victims as described in the text. Furthermore, discuss the types of injuries commonly associated with this form of abuse, including the significance of defensive wounds and hashing-suit patterns.", "guidance": "Formulate a comprehensive essay response for each."},
    {"question": "Compare and contrast the Family Developmental Theory and the Structural-Functional Theory. What are the primary functions and developmental stages each theory outlines, and what are their respective limitations?", "guidance": "Formulate a comprehensive essay response for each."},
    {"question": "Explain how stress impacts the body, referencing the physiological responses (e.g., increased cortisol levels, heart rate) and the body''s compensatory mechanisms. Discuss how cells adapt to stress through processes like atrophy, hypertrophy, and hyperplasia.", "guidance": "Formulate a comprehensive essay response for each."},
    {"question": "Describe the principles of Cognitive-Behavioral Therapy (CBT) and Acceptance and Commitment Therapy (ACT). How do these psychosocial interventions differ in their approach to helping individuals manage dysfunctional thoughts, feelings, and behaviors?", "guidance": "Formulate a comprehensive essay response for each."}
  ]'::jsonb,
  '[
    {"term": "Acceptance and Commitment Therapy (ACT)", "definition": "A \"third wave\" of CBT that emphasizes contextual and experiential learning through psychological flexibility, focusing on accepting thoughts and feelings without judgment rather than avoiding them."},
    {"term": "Aggression", "definition": "A communication or threat of an intended act of violence that often occurs before the violent act itself. It can include behaviors like shouting, invasion of personal space, and prolonged eye contact."},
    {"term": "Anorexia Nervosa", "definition": "An eating disorder characterized by a morbid fear of obesity and a refusal to maintain a normal body weight, leading to a profound health risk."},
    {"term": "Anticipatory Grief", "definition": "The mental, social, and somatic reactions of an individual as they prepare for a perceived future loss. This process often takes place ahead of the actual loss."},
    {"term": "Anxiety", "definition": "A human emotion and experience that everyone has at some point during their life, characterized by feelings of uncertainty, helplessness, isolation, agitation, and insecurity."},
    {"term": "Atrophy", "definition": "Cells swelling, leading to an overall decrease in the size of the affected organ."},
    {"term": "Auscultation", "definition": "The act of listening to sounds within the body through either the bell or the diaphragm of the stethoscope."},
    {"term": "Authoritarian (Parenting Style)", "definition": "Parents desire obedience without question, tend toward harsh punishments, and use their power to make their children''s decisions."},
    {"term": "Authoritative (Parenting Style)", "definition": "Parents provide boundaries and expect obedience, but take love and the child''s unique position into consideration. They enforce rules consistently but also encourage independence and confidence."},
    {"term": "Behavior Modification", "definition": "A type of systematic therapy that works toward the goal of replacing maladaptive behaviors with adaptive behaviors, often using positive reinforcement."},
    {"term": "Bereavement", "definition": "The emotional and mental state associated with having suffered a personal loss."},
    {"term": "Bulimia Nervosa", "definition": "An eating disorder characterized by binge eating followed by vomiting at least 2 times a month for at least 3 months, often accompanied by feelings of lack of control during binging."},
    {"term": "Chemical Restraints", "definition": "The use of pharmacological sedatives to manage an individual''s behavior problems, indicated only when severe agitation or violence puts the patient at risk for injury."},
    {"term": "Cognitive-Behavioral Therapy (CBT)", "definition": "A psychosocial intervention that focuses on the impact that thoughts have on behavior and feelings, empowering the individual to use the power of mental thought to alter perceptions."},
    {"term": "Cognitive Distortions", "definition": "Automatic, irrational thoughts that are a core concept in Aaron Beck''s Cognitive Therapy."},
    {"term": "Depression", "definition": "A mood disorder characterized by profound feelings of sadness and withdrawal, often following a death or stressful event. A major depressive episode is diagnosed when symptoms persist for at least two weeks."},
    {"term": "Disenfranchised Grief", "definition": "A type of grieving that occurs when the loss being experienced cannot be openly acknowledged, publicly mourned, or socially supported."},
    {"term": "Family Developmental Theory", "definition": "A theory that posits families move through different developmental stages, which are accompanied by certain tasks (e.g., Marriage, Birth of first child, Preschool children)."},
    {"term": "Family Stress Theory", "definition": "A theory that models how families cope with stressors, considering the resources available to the family and how the family perceives the stressor."},
    {"term": "Family Systems Theory", "definition": "A theory viewing the family as a system where members are interdependent; when one member makes a change, other family members will change to maintain equilibrium."},
    {"term": "Grief", "definition": "An emotional response to a loss that begins at the time a loss is anticipated and continues on an individual timetable. It is not an orderly and predictable process."},
    {"term": "Hospice Care", "definition": "Care that supports the patient and family through the dying process for individuals deemed terminal with a life expectancy of six months or less."},
    {"term": "Hyperplasia", "definition": "The cells are changed in appearance as a result of irritation over an extended period of time, sometimes leading to malignancy."},
    {"term": "Hypertrophy", "definition": "Cells and organ size increase in response to stress."},
    {"term": "Indifferent/Uninvolved (Parenting Style)", "definition": "Parents who spend as little time as possible with their children, are self-involved, and provide little guidance."},
    {"term": "Indulgent/Permissive (Parenting Style)", "definition": "Parents who stay involved with their children but have few rules, leading to children who have difficulty setting their own limits and are not responsible."},
    {"term": "Loss", "definition": "The blanket term used to denote the absence of a valued object, person, status, attribute, or individual function that was present before."},
    {"term": "Mourning", "definition": "A public grief response for the death of a loved one, shaped by personal and cultural belief systems."},
    {"term": "Palliative Care", "definition": "Care that attempts to make the rest of the patient''s life as comfortable as possible by treating distressing physical and psychosocial symptoms associated with chronic disease."},
    {"term": "Palpation", "definition": "The use of palpation to provide valuable details during physical assessment of the patient, such as assessing texture, identifying tenderness, or feeling for masses."},
    {"term": "Panic Attacks", "definition": "Short episodes (peaking in 5-10 minutes) of intense anxiety that can result in a wide variety of symptoms such as dyspnea, palpitations, nausea, and chest pain."},
    {"term": "Percussion", "definition": "The act of striking a part of the body to set the chest or abdominal wall into motion, producing a sound that helps to identify whether the tissue is solid or filled with air or fluid."},
    {"term": "Physical Restraints", "definition": "Restraints used to restrict movement and activity when other methods of controlling patient behavior have failed."},
    {"term": "Post-traumatic Stress Disorder (PTSD)", "definition": "A condition where patients who experience a traumatic event may re-experience the trauma through distressing thoughts and recollections."},
    {"term": "Recovery Model", "definition": "An approach to mental health treatment that shifts control of treatment options to the patient rather than the physician dictating the plan of care."},
    {"term": "Resiliency Model", "definition": "A model that assumes some families develop strength over time by facing challenges common to all families."},
    {"term": "Solution-Focused Therapy", "definition": "A brief form of therapy that directs from how problems are to what is changeable, focusing on identifying goals and finding solutions in the real world."},
    {"term": "Spirituality", "definition": "Provides a connection of the self to a higher power and a way of finding meaning in life, offering guidance for behavior and clarifying one''s purpose."},
    {"term": "Stress", "definition": "A condition that causes a number of physical and psychological changes within the body, including increased cortisol levels and heart rate."},
    {"term": "Structural-Functional Theory", "definition": "A theory viewing the family as a social system that serves society by performing functions like affection, socialization, reproduction, economic support, and health care."},
    {"term": "Substance Abuse", "definition": "The chronic or habitual abuse of drugs, medicines, or alcohol that causes mental and physical problems for the abuser and family."},
    {"term": "Tactile Fremitus", "definition": "The art of speaking causes the chest wall to vibrate. This vibration can be felt by placing your hands lightly on the chest wall."},
    {"term": "Temperament", "definition": "The way a person relates or responds to his environment and the people around him. It is inborn but can be affected by how parents relate to the child/adolescent."},
    {"term": "Therapeutic Communication", "definition": "Communication that begins with respect for the patient/family and the assumption that all behavior is goal-directed and has meaning. It involves techniques like empathy and encouragement."},
    {"term": "Trauma-Informed Care", "definition": "An approach to care based on the premise that many individuals have experienced some sort of trauma and therefore every patient should be approached with sensitivity and care."},
    {"term": "Violence", "definition": "A physical act perpetrated against an inanimate object, animal, or other person with the intent to cause harm."}
  ]'::jsonb
)
ON CONFLICT DO NOTHING;

-- Insert Episode 6: Basic Care and Comfort
INSERT INTO study_guides (episode_id, title, short_answer_questions, essay_questions, glossary)
VALUES (
  6,
  'Study Guide: Basic Care and Comfort',
  '[
    {"question": "Describe the purpose of occupational therapy and name its creator.", "answer": "The purpose of occupational therapy is to provide disabled individuals with the skills needed to live as fully and independently as possible after their injury or illness. The therapist develops interventions tailored to the patient''s disability. William Rush Dunton is considered the creator of occupational therapy."},
    {"question": "What are the key differences between a long-term acute care hospital and a comprehensive rehabilitation center?", "answer": "A long-term acute care hospital is for patients with complex needs, such as those on dialysis or ventilation, who require medical support alongside rehabilitation. A comprehensive rehabilitation center has a \"team\" of professionals (therapists, social workers, etc.) and offers intensive therapy to patients who can tolerate several hours of it daily."},
    {"question": "Explain the three-point gait used when teaching a patient to walk with crutches.", "answer": "The three-point gait is used for an injured extremity. Both crutches are advanced together, and then the non-injured leg advances to or past the crutches. This gait allows the patient to move without putting weight on the injured leg."},
    {"question": "What is bladder retraining and what is its primary goal?", "answer": "Bladder retraining is a behavioral modification program that teaches people to control the urge to urinate. Its goal is to restore normal bladder function, which typically takes about three months, by progressively lengthening the time between urination."},
    {"question": "Differentiate between soluble and insoluble fiber, providing a food source example for each.", "answer": "Soluble fiber dissolves in liquids to form a gel-like substance that slows the movement of stool; sources include bananas, potatoes, and apples. Insoluble fiber changes little during digestion and increases the speed of stool movement through the colon; sources include wheat bran, whole grains, and seeds."},
    {"question": "According to the National Pressure Injury Advisory Panel, what is a Stage IV pressure injury?", "answer": "A Stage IV pressure injury involves full-thickness tissue loss with necrosis into muscle, bone, tendons, and/or joints. This is a deep tissue injury where underlying structures are exposed."},
    {"question": "What is the primary cause of pressure injuries, and what three factors contribute to it?", "answer": "The primary cause of pressure injuries is pressure. The three contributing factors are pressure intensity (the amount of pressure), pressure duration (the length of time pressure is applied), and tissue tolerance (the ability of the skin and tissue to endure pressure)."},
    {"question": "Define \"shear\" and \"friction\" as they relate to tissue damage.", "answer": "Shear occurs when the skin stays in place while underlying tissue moves, causing stretching and occlusion of underlying vessels. Friction is a significant cause of pressure injuries that acts with gravity to cause shear, resulting in damage to the epidermis and dermis, which is often referred to as \"sheet burn.\""},
    {"question": "Name two types of whole medical systems and briefly describe their philosophies.", "answer": "Homeopathic medicine is a European system that uses small amounts of diluted herbs and supplements to help the body heal. Naturopathic medicine is a European system that uses natural healing forces, including herbs, massage, acupuncture, and diet, to support the natural healing processes of the body."},
    {"question": "Describe the three main physiological processes of postmortem decomposition.", "answer": "The three main processes are livor mortis, the discoloration and staining of tissue from blood settling; rigor mortis, the stiffening of the body due to the depletion of adenosine triphosphate (ATP); and algor mortis, the cooling of the body to ambient temperature."}
  ]'::jsonb,
  '[
    {"question": "A patient has been hospitalized after a stroke and requires significant rehabilitation. Discuss the comprehensive, interdisciplinary approach to their care, outlining the assessment process, potential rehabilitation settings, and the specific role of occupational therapy.", "guidance": "Develop a detailed response to each of the following prompts, drawing exclusively on information from the source text."},
    {"question": "Compare and contrast the different methods for bladder and bowel training. What are the key principles behind each, and what patient populations might benefit most from techniques like prompted voiding, bladder retraining, scheduled defecation, and Kegel exercises?", "guidance": "Develop a detailed response to each of the following prompts, drawing exclusively on information from the source text."},
    {"question": "A patient is identified as being at high risk for developing pressure injuries. Outline a detailed prevention plan based on the source material, addressing pressure redistribution, control of shear and friction, mobility, and incontinence management.", "guidance": "Develop a detailed response to each of the following prompts, drawing exclusively on information from the source text."},
    {"question": "Discuss the role of alternative, complementary, and non-pharmacologic interventions in patient care. Using the source text, explain the various categories (e.g., mind-body, whole medical systems, temperature-controlled therapies) and provide specific examples of how they are used for pain relief and healing.", "guidance": "Develop a detailed response to each of the following prompts, drawing exclusively on information from the source text."},
    {"question": "Describe the process of postmortem care from the moment of death through documentation. What are the key physiological changes that occur in the body, and what are the provider''s responsibilities to both the deceased and their family?", "guidance": "Develop a detailed response to each of the following prompts, drawing exclusively on information from the source text."}
  ]'::jsonb,
  '[
    {"term": "Activities of Daily Living (ADLs)", "definition": "A group of activities used to evaluate a patient''s return to normal functional status and monitor progress during rehabilitation."},
    {"term": "Acupuncture", "definition": "An alternative system of medical practice that involves placing needles in specific body areas to restore balance and the flow of qi."},
    {"term": "Algor Mortis", "definition": "The postmortem cooling of the body to ambient temperature. Body temperature is about 37°C, but body functions cease at death."},
    {"term": "Ayurveda", "definition": "An Indian system that tries to bring the spirit into harmony with the mind and body, using methods like meditation, yoga, diet, and lifestyle changes."},
    {"term": "Bladder Retraining", "definition": "A behavioral modification program that teaches people to inhibit the urge to urinate and urinate according to an established schedule, with the goal of restoring normal bladder function."},
    {"term": "CEAP Classification", "definition": "A classification system for chronic venous disorders based on Clinical, Etiologic, Anatomic, and Pathophysiological factors."},
    {"term": "Chinese Medicine", "definition": "A system that focuses on natural forces within the body to cure disease by using herbs, acupuncture, and meditation."},
    {"term": "Comprehensive Rehabilitation Center", "definition": "An inpatient facility that has a team of professionals and offers intensive therapy to patients who can tolerate several hours of therapy per day."},
    {"term": "Conduction", "definition": "The conveyance of heat through direct contact with the skin, such as with a hot bottle, ice packs, and electrical stimulation."},
    {"term": "Convection", "definition": "The transfer of heat in a liquid or gas by circulation of heated particles, such as in whirlpools and paraffin baths."},
    {"term": "Conversion", "definition": "A process that results from converting a form of energy into heat, such as with diathermy."},
    {"term": "Cryotherapy", "definition": "The use of cool temperatures for healing."},
    {"term": "Cupping", "definition": "An ancient practice where dry, cupping cups are heated and placed on the skin to reduce pain, promote healing, and improve circulation."},
    {"term": "Envelopment", "definition": "The ability of a support surface to conform to the shape of the body without increasing pressure."},
    {"term": "Evaporation", "definition": "Cooling caused by liquids that evaporate into gases on the skin with a resultant cooling effect, such as with perspiration or vapo-coolant sprays."},
    {"term": "Friction", "definition": "A force that acts with gravity to cause shear, resulting in damage to the epidermis and dermis, also known as \"sheet burn.\""},
    {"term": "Homeopathic Medicine", "definition": "A European system that uses small amounts of diluted herbs and supplements to help the body heal itself."},
    {"term": "Immersion", "definition": "The depth a body sinks into a support surface."},
    {"term": "Insoluble Fiber", "definition": "Fiber that changes little with the digestive process and increases the speed of stool through the colon. Sources include wheat bran, whole grains, and fruits/vegetables."},
    {"term": "Instrumental ADLs", "definition": "The second group of ADLs, containing activities such as shopping, answering the phone, and managing money, which are required for independent living."},
    {"term": "Kegel Exercises", "definition": "An exercise involving the increase of strength of the pelvic floor muscles for urinary and fecal incontinence."},
    {"term": "Livor Mortis", "definition": "The postmortem process where blood settles in dependent parts of the body, causing purplish discoloration and staining of tissue."},
    {"term": "Long-term Acute Care Hospital", "definition": "A rehabilitation setting for patients who need medical treatment, such as dialysis or ventilation, alongside rehabilitation."},
    {"term": "Modified Wagner Ulcer Classification System", "definition": "A system that divides foot ulcers into six grades based on lesion depth, osteomyelitis or gangrene, infection, ischemia, and neuropathy."},
    {"term": "Naturopathic Medicine", "definition": "A European system that uses various natural means (herbs, massage, etc.) to support the natural healing forces of the body."},
    {"term": "Nociceptors", "definition": "Nerve endings that respond to painful stimuli."},
    {"term": "Occupational Therapy", "definition": "The use of creative activities in the treatment of disabled individuals, with the purpose of providing them with skills to live as fully and independently as possible."},
    {"term": "Outpatient Rehabilitation", "definition": "A setting designed for the functioning patient who can return home after rehabilitation sessions."},
    {"term": "Personal or Physical ADLs", "definition": "The first group of ADLs, containing daily activities that relate to a patient''s ability to take care of themselves."},
    {"term": "Pressure Injury", "definition": "Injuries resulting from pressure with or without shear and/or friction over bony prominences."},
    {"term": "Prompted Viding", "definition": "A communication protocol for people with mild to moderate cognitive impairment that uses positive reinforcement for recognizing being wet or dry, staying dry, urinating, and drinking liquids."},
    {"term": "Radiation", "definition": "The transfer of heat from a source to an object without the source touching the object, such as with infrared or ultraviolet light."},
    {"term": "Rehabilitation", "definition": "An area of health care dedicated to helping patients improve and/or restore functions of the body and mind that have been impaired."},
    {"term": "Rigor Mortis", "definition": "The postmortem process where the body tends to be flaccid, then becomes muscularly contracted and stiff, caused by depletion of ATP."},
    {"term": "S(AD) SAD Classification System", "definition": "A classification system for lower-extremity neuropathic disease that stands for Size (Area and Depth), Sepsis, Arteriopathy, and Denervation."},
    {"term": "Shear", "definition": "A force that occurs when the skin stays in place and the underlying tissue in the deep fascia over the bony prominence stretches and slides, damaging vessels."},
    {"term": "Soluble Fiber", "definition": "Fiber that dissolves or liquefies to form a gel-like substance that slows the movement of stool. Sources include bananas, potatoes, dried beans, nuts, and apples."},
    {"term": "Subacute Care Unit", "definition": "A rehabilitation setting appropriate for patients who require more limited treatment, such as cancer patients."},
    {"term": "Superficial Heat", "definition": "Heat that is externally applied and penetrates only the superficial layers of the skin (1-2 cm deep)."},
    {"term": "TENS (Transcutaneous electrical nerve stimulation)", "definition": "A therapy that sends low-voltage electrical signals from a small device to block or scramble pain signals that transfer only to the nerve sensation."},
    {"term": "Thermotherapy", "definition": "The use of heat for healing."},
    {"term": "Tissue Interface Pressure", "definition": "The amount of pressure exerted on the body by a surface that the body is lying or sitting on."},
    {"term": "Visualization", "definition": "A method used to reduce anxiety and promote healing, including techniques like guided imagery, self-hypnosis tapes, or concentrating on breathing."},
    {"term": "Whole Medical Systems", "definition": "Different philosophies and methods of explaining and treating health and illness, such as homeopathic, naturopathic, Chinese, and Ayurveda medicine."}
  ]'::jsonb
)
ON CONFLICT DO NOTHING;
